head.script:
//imports("uiplugin._popup");
scwin.hpcmFileNm = "";
scwin.pgeNo = "";
/**
 * 화면 초기화에 필요한 로직을 수행한다.
 */
scwin.initScreen = function() {
	scwin.inqireHpcm();
};

scwin.inqireHpcm = function() {
	var requestData = {};
	var option = {
		action : "zz/authmng/retrieveHpcm.do",
		reqData : requestData,
		resData : dltLeftMenuInfo,
		success : "scwin.inqireHpcmCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

scwin.inqireHpcmCallback = function() {
	// 예외처리 및 데이터 바인딩
	var leftMenuInfo = dltLeftMenuInfo.getAllJSON();
	var targetMenuId = "ECSEC510000";
	leftMenuInfo = leftMenuInfo.filter(obj => !obj.menuId.startsWith("ECSEC5") || obj.menuId == targetMenuId);
	leftMenuInfo[leftMenuInfo.findIndex(obj => obj.menuId == targetMenuId)].menuNm = "유역별 종합현황";
	dltLeftMenuInfo.setJSON(leftMenuInfo);
	var upperMenu = dltLeftMenuInfo.getAllJSON().filter(obj => !obj.scrinId);
	Object.keys(mf_dmaLeftMenuTit.getJSON()).forEach(item => {
		dmaLeftMenuTit.set(item, (upperMenu.find(obj => obj.menuId == item) || 0).menuNm);
	});

	var pparam;
	if($p.getPopupParam()){
		pparam = JSON.parse($p.getPopupParam());
	} else{
		pparam = JSON.parse($w.getPopupParam());
	}
	scwin.hpcmFileNm = pparam.data.guideHtml;
	scwin.pgeNo = pparam.data.pageNo;

	if (scwin.hpcmFileNm == "") {
		scwin.hpcmFileNm = $p.getParameter("guideHtml");
	}

	if (scwin.pgeNo == "") {
		scwin.pgeNo = $p.getParameter("pageNo");
	}
	$(document).ready(function() {
		tabControl1.trigger("onchange", [$p.$("#tabControl1>ul>li:eq(0)").attr("id"), 0, tabControl1.getTabID(0)]);
		scwin.HpcmViewer(scwin.hpcmFileNm, scwin.pgeNo);
	});
};

scwin.HpcmViewer = function (hpcmFileNm, pgeNo) {
	var idx = tabControl1.getTabIndex(hpcmFileNm);
	if (idx < 0) {
		return;
	}
	tabControl1.setSelectedTabIndex(idx);

	var iframe = tabControl1.getChildren()[idx].getChildren()[1];
	iframe.setSrc("/hpcm/" + hpcmFileNm + ".html?#" + pgeNo);
};

scwin.HpcmViewer2 = function (str, str1) {
	tabControl1.setSelectedTabIndex(tabControl1.getTabIndex(str));
	eval($p.id+"helpHtml" + "_" + tabControl1.getTabIndex(str)).setSrc("/hpcm/" + str + ".html?#" + str1);
};

scwin.tabControl1_onchange = function(tabId, idx, userTabID) {
	var leftMenuTit = dmaLeftMenuTit.get(userTabID);
	if (!leftMenuTit) {
		return;
	}

	var leftMenuList = dltLeftMenuInfo.getMatchedJSON("hpcmFileNm", userTabID, true);
	var contentId = this.getChildren()[idx].id;
	var obj = $p.$('#'+ contentId);
	var leftMenu= obj.find(".sub_title>span").text(leftMenuTit).next();
	leftMenu.empty();
	$.each(leftMenuList, function(i,o) {
		var item = $('<li class="w2group"><a class="w2anchor2 " href="javascript:void(null);">' + o.menuNm + '</a></li>');
		item.on("click", function(){
			scwin.HpcmViewer(o.hpcmFileNm, o.pgeNo);
		});
		leftMenu.append(item);
	});
	if (leftMenuList.length > 0) {
		scwin.HpcmViewer(leftMenuList[0].hpcmFileNm, "pf01");
	}
};
